    account.url ? { href: account.url, label: SOCIAL_LINK_LABELS.website } : null,
    account.facebook ? { href: account.facebook, label: SOCIAL_LINK_LABELS.facebook } : null,
    account.instagram ? { href: account.instagram, label: SOCIAL_LINK_LABELS.instagram } : null,
    account.twitter ? { href: account.twitter, label: SOCIAL_LINK_LABELS.twitter } : null,
    account.rumble ? { href: account.rumble, label: SOCIAL_LINK_LABELS.rumble } : null,
  ].filter(
    (link): link is { href: string; label: string } =>
      typeof link?.href === 'string' && typeof link.label === 'string'
  );
  const socialValue =
    socialLinks.length > 0 ? (
      <Stack spacing={1}>
        {socialLinks.map((link) => (
          <Link color="blue.600" href={link.href} isExternal key={link.href} fontSize="sm">
            {link.label}
          </Link>
        ))}
      </Stack>
    ) : undefined;
  const publicAddress = addressTypes.public || addressTypes.other;
  const legalAddress = addressTypes.legal;
  const formatAddressValue = (value?: Parameters<typeof getAddressLabel>[0]) =>
    value ? (
      <Paragraph whiteSpace="pre-line" fontSize="sm" textColor="neutral.900">
        {getAddressLabel(value, true)}
      </Paragraph>
    ) : undefined;

  const renderStepSection = (step: ApplicationStepDefinition) => {
    const stepKey = getStepKeyFromPath(step.path);

    if (!stepKey || stepKey === 'submit_application') {
      return null;
    }

    const fields: FieldData[] = [];

    switch (stepKey) {
      case 'name_and_type':
        fields.push(
          { id: 'displayName', label: 'Display name', value: account.displayName },
          {
            id: 'legalName',
            label: 'Legal name',
            value: account.name ?? undefined,
            isMissing: !account.name,
          },
          {
            id: 'category',
            label: 'Account category',
            value: categoryLabel,
            isMissing: !account.category,
          }
        );
        break;
      case 'category':
        fields.push(
          { id: 'subCategory', label: 'Subcategory', value: subCategoryLabel },
          {
            id: 'subCategoryType',
            label: 'Subcategory type',
            value: subCategoryTypeLabel,
            isMissing: !account.subCategoryType,
          },
          {
            id: 'directoryName',
            label: 'Directory name',
            value: account.directoryName ?? undefined,
          },
          { id: 'politicalParty', label: 'Political party', value: politicalPartyLabel }
        );
        break;
      case 'onboarding_survey': {
        const websiteStatusValue = currentOnboardingSurvey?.whenWillWebsiteGoLive
          ? WEBSITE_STATUS_LABELS[currentOnboardingSurvey.whenWillWebsiteGoLive] ??
            currentOnboardingSurvey.whenWillWebsiteGoLive
          : undefined;
        const websiteStatusIsMissing =
          Boolean(currentOnboardingSurvey?.useLinkFromWebsite) &&
          !currentOnboardingSurvey?.whenWillWebsiteGoLive;
        const websiteUrlIsMissing =
          Boolean(currentOnboardingSurvey?.useLinkFromWebsite) &&
          !currentOnboardingSurvey?.linkedFromWebsiteUrl;

        fields.push(
          {
            id: 'howDidYouHear',
            label: 'How did you hear about Anedot?',
            value: currentOnboardingSurvey?.howDidYouHearAboutAnedot
              ? HOW_DID_YOU_HEAR_LABELS[currentOnboardingSurvey.howDidYouHearAboutAnedot] ??
                currentOnboardingSurvey.howDidYouHearAboutAnedot
              : undefined,
            isMissing: !currentOnboardingSurvey?.howDidYouHearAboutAnedot,
          },
          {
            id: 'referenceName',
            label: 'Reference name',
            value: currentOnboardingSurvey?.consultantFriendOtherName || undefined,
          },
          {
            id: 'annualProcessingVolume',
            label: 'Estimated annual processing volume',
            value: PROCESSING_VOLUME_OPTIONS.find(
              ({ value }) => value === currentOnboardingSurvey?.annualProcessingVolume
            )?.label,
            isMissing: !currentOnboardingSurvey?.annualProcessingVolume,
          },
          {
            id: 'previousPlatform',
            label: 'Previous platform',
            value: currentOnboardingSurvey?.previousPlatform || undefined,
          },
          {
            id: 'websiteStatus',
            label: 'Website status',
            value: websiteStatusValue,
            isMissing: websiteStatusIsMissing,
          },
          {
            id: 'websiteUrl',
            label: 'Website URL',
            value: currentOnboardingSurvey?.linkedFromWebsiteUrl || undefined,
            isMissing: websiteUrlIsMissing,
          },
          { id: 'useCases', label: "Where you'll use Anedot", value: onboardingUseCasesValue }
        );
        break;
      }
      case 'support_profile':
        fields.push(
          {
            id: 'softDescriptor',
            label: 'Statement descriptor',
            value: account.softDescriptor ?? undefined,
            isMissing: !account.softDescriptor,
          },
          {
            id: 'supportEmail',
            label: 'Support email',
            value: account.email ?? undefined,
            isMissing: !account.email,
          },
          {
            id: 'supportPhone',
            label: 'Support phone',
            value: account.phone ? formatPhone(account.phone) : undefined,
            isMissing: !account.phone,
          },
          { id: 'website', label: 'Website', value: account.url || undefined },
          { id: 'socialProfiles', label: 'Social profiles', value: socialValue },
          {
            id: 'publicAddress',
            label: 'Public address',
            value: formatAddressValue(publicAddress),
          }
        );
        break;
      case 'legal_entity':
        fields.push(
          {
            id: 'legalEntityName',
            label: 'Legal entity name',
            value: account.name ?? undefined,
            isMissing: !account.name,
          },
          {
            id: 'taxId',
            label: 'Tax ID (EIN)',
            value: account.taxid ?? undefined,
            isMissing: !account.taxid,
          },
          {
            id: 'establishedDate',
            label: 'Date established',
            value: account.establishedDate ? formatDate(account.establishedDate, 'PP') : undefined,
            isMissing: !account.establishedDate,
          },
          {
            id: 'missionStatement',
            label: 'Mission statement',
            value: account.description ?? undefined,
            isMissing: !account.description,
          },
          { id: 'fecId', label: 'FEC ID', value: account.fecCommitteeId ?? undefined },
          {
            id: 'legalAddress',
            label: 'Legal address',
            value: formatAddressValue(legalAddress),
            isMissing: !legalAddress,
          }
        );
        break;
      case 'documentation': {
        const accountCategory = account.category as AccountCategory | undefined;
        const documents =
          accountCategory && DOCUMENTS_BY_CATEGORY[accountCategory]
            ? DOCUMENTS_BY_CATEGORY[accountCategory]
            : undefined;

        if (!documents) {
          fields.push({
            id: 'documents',
            label: 'Required documents',
            value: 'Required',
            isMissing: true,
          });
          break;
        }

        const isW9Required = account.category === 'vendor';

        documents.forEach((documentType) => {
          const currentFile = accountDocuments?.find((doc) => doc.documentType === documentType);
          const isRequired =
            documentType === 'irs_cp_575' || (documentType === 'irs_w9' && isW9Required);

          fields.push({
            id: documentType,
            label: formatDocumentLabel(documentType),
            value: currentFile ? `Uploaded (${currentFile.file.name})` : 'Not uploaded yet',
            isMissing: isRequired && !currentFile,
          });
        });
        break;
      }
      case 'connect_bank': {
        const formattedAccounts = (bankAccounts ?? []).map((bankAccount) => (
          <Paragraph textColor="neutral.900" fontSize="sm" key={bankAccount.id}>
            {formatBankAccountLabel(bankAccount)}
          </Paragraph>
        ));

        fields.push({
          id: 'bankAccounts',
          label: 'Connected bank accounts',
          value: formattedAccounts.length ? <Stack spacing={1}>{formattedAccounts}</Stack> : undefined,
          isMissing: formattedAccounts.length === 0,
        });
        break;
      }
      case 'financial_authority': {
        const signatoryName = [account.signatory?.firstName, account.signatory?.lastName]
          .filter(Boolean)
          .join(' ')
          .trim();

        fields.push(
          { id: 'signatoryName', label: 'Account owner', value: signatoryName || undefined },
          {
            id: 'signatoryEmail',
            label: 'Owner email',
            value: account.signatory?.email ?? undefined,
          },
          {
            id: 'signature',
            label: 'Signed authorization',
            value: account.signature?.url ? 'Uploaded' : 'Not signed yet',
            isMissing: !account.signature?.url,
          }
        );
        break;
      }
      case 'nonprofit_attestation':
        fields.push(
          {
            id: 'attestationTitle',
            label: 'Officer title',
            value: account.title501c4 ?? undefined,
            isMissing: !account.title501c4,
          },
          {
            id: 'attestationSignature',
            label: '501c4 attestation',
            value: account.signature501c4?.url ? 'Uploaded' : 'Not signed yet',
            isMissing: !account.signature501c4?.url,
          }
        );
        break;
      case 'kyc_verification':
        fields.push(
          {
            id: 'kycOwners',
            label: 'Beneficial owners',
            value: undefined,
            isMissing: true,
          },
          {
            id: 'kycSignature',
            label: 'KYC signature',
            value: undefined,
            isMissing: true,
          }
        );
        break;
      default:
        break;
    }

    if (!fields.length) {
      return null;
    }

    const missingFields = fields.filter((field) => field.isMissing).map((field) => field.label);

    return (
      <StepSection
        key={step.text}
        missingFields={missingFields}
        onEdit={navigateToStep(step.path)}
        step={step}
      >
        {fields.map((field) => (
          <Field key={field.id} isMissing={field.isMissing} label={field.label} value={field.value} />
        ))}
      </StepSection>
    );
  };

  const renderedSections = steps
    .map((step) => renderStepSection(step))
    .filter((section): section is JSX.Element => Boolean(section));

  if (!renderedSections.length) {
    return null;
  }

  return (
    <Panel display="flex" flexDirection="column" gap={6} variant="primary">
      <Paragraph textColor="neutral.600">Take a moment to review your application.</Paragraph>
      <Stack spacing={6}>{renderedSections}</Stack>
    </Panel>
  );
};
