} from '@chakra-ui/react';
import { Account } from '@domain/account';
import { AccountCategory } from '@domain/accountCategory';
import { DOCUMENTS_BY_CATEGORY, DocumentType } from '@domain/accountDocument';
import { BankAccount } from '@domain/bankAccount';
import { getAddressTypes } from '@pages/components/OrganizationInformation/OrganizationInformation';
import { useGetAccountDocuments } from '@state/accountDocuments';
import { useGetAddresses } from '@state/addresses';
import { useGetAllBankAccounts } from '@state/bank_accounts/helpers';
