import { formatDate, formatPhone, getAddressLabel } from '@ui/utils';
import { ReactElement, ReactNode, useMemo } from 'react';
import { generatePath, useNavigate } from 'react-router-dom';
import { ApplicationStepDefinition, OrganizationApplicationStep } from '../useSteps';

const CATEGORY_LABELS: Record<AccountCategory, string> = {
  'church-ministry': 'Church / ministry',
  education: 'Education',
  nonprofit: 'Nonprofit',
  political: 'Political',
  vendor: 'Vendor',
};

const isAccountCategoryValue = (value: string | null | undefined): value is AccountCategory => {
  return (
    value === 'church-ministry' ||
    value === 'education' ||
    value === 'nonprofit' ||
    value === 'political' ||
    value === 'vendor'
  );
};

const PROCESSING_VOLUME_OPTIONS = [
  { label: 'Less than $500', value: '0' },
  { label: '$500 - $5,000', value: '500' },
  { label: '$5,000 - $10,000', value: '5000' },
  { label: '$10,000 - $50,000', value: '10000' },
  { label: '$50,000 - $100,000', value: '50000' },
  { label: '$100,000 - $250,000', value: '100000' },
  { label: '$250,000 - $500,000', value: '250000' },
  { label: '$500,000 - $1M', value: '500000' },
  { label: '$1M+', value: '1000000' },
];

const HOW_DID_YOU_HEAR_LABELS: Record<string, string> = {
  advertisement: 'Advertisement',
  aiTool: 'AI tool (e.g., ChatGPT, Grok, Gemini)',
  capterra: 'Capterra',
  consultant: 'Consultant',
  customer: 'Anedot customer',
  existingPrevious: 'Existing user / Used previously',
  friend: 'Friend',
  g2: 'G2',
  google: 'Google search',
  other: 'Other',
  podcast: 'Podcast',
  socialMedia: 'Social media',
  softwareAdvice: 'Software Advice',
  teamMember: 'Anedot team member',
  youTube: 'YouTube',
};

const USE_CASE_LABELS = {
  useEmails: 'Emails',
  useInternal: 'Internal (phone, mail, etc.)',
  useLinkFromWebsite: 'Link from website',
  useSocialMedia: 'Social media',
};

const WEBSITE_STATUS_LABELS: Record<string, string> = {
  '1-2 months': '1-2 months',
  '1-2 weeks': '1-2 weeks',
  '3+ months': '3+ months',
  '3-4 weeks': '3-4 weeks',
  'Already live': 'Already live',
  'This week': 'This week',
};

const DOCUMENT_LABELS: Record<DocumentType, string> = {
  annual_report: 'Annual report',
  articles_of_incorporation: 'Articles of incorporation',
  certificate_of_good_standing: 'Certificate of good standing',
  election_filing: 'Election filing',
  form_1023: 'Form 1023',
  irs_501c: 'IRS 501(c)',
  irs_8976_or_1023: 'IRS 8976 or 1023',
  irs_cp_575: 'IRS CP-575',
  irs_w9: 'IRS W-9',
  tax_document: 'Tax document',
  voided_check: 'Voided check',
};

const SOCIAL_LINK_LABELS = {
  facebook: 'Facebook',
  instagram: 'Instagram',
  twitter: 'Twitter',
  website: 'Website',
  rumble: 'Rumble',
};

const hasRenderableValue = (value?: ReactNode) => {
  if (typeof value === 'number') {
    return true;
  }

  if (typeof value === 'string') {
    return value.trim().length > 0;
  }

  if (Array.isArray(value)) {
    return value.length > 0;
  }

  return !!value;
};

const formatBankAccountLabel = (bankAccount: BankAccount) => {
  const typeLabel =
    bankAccount.accountType === 'savings'
      ? 'Savings'
      : bankAccount.accountType === 'checking'
        ? 'Checking'
        : undefined;
  const accountDigits = bankAccount.accountNumber?.slice(-4);
  const nickname = bankAccount.nickname || typeLabel;
  const parts = [
    bankAccount.bankName ?? 'Bank account',
    nickname ? `• ${nickname}` : null,
    accountDigits ? `• ••••${accountDigits}` : null,
  ].filter((segment): segment is string => typeof segment === 'string');

  return parts.join(' ');
};

const formatDocumentLabel = (documentType: DocumentType) =>
  DOCUMENT_LABELS[documentType] ??
  documentType
    .split('_')
    .map((segment) => segment.toUpperCase())
    .join(' ');

const isOrganizationApplicationStep = (
  value: string | null | undefined
): value is OrganizationApplicationStep => {
  if (!value) {
    return false;
  }

  return (
    value === 'name_and_type' ||
    value === 'category' ||
    value === 'onboarding_survey' ||
    value === 'support_profile' ||
    value === 'legal_entity' ||
    value === 'documentation' ||
    value === 'connect_bank' ||
    value === 'financial_authority' ||
    value === 'nonprofit_attestation' ||
    value === 'kyc_verification' ||
    value === 'submit_application'
  );
};

const getStepKeyFromPath = (
  path: ApplicationStepDefinition['path']
): OrganizationApplicationStep | null => {
  if (path === '') {
    return 'name_and_type';
  }

  return isOrganizationApplicationStep(path) ? path : null;
};

const getStatusMeta = (status: StepNavigationLinkStatus) => {
  switch (status) {
    case 'complete':
      return { colorScheme: 'green', label: '' };
    case 'current':
      return { colorScheme: 'blue', label: 'In progress' };
    case 'error':
      return { colorScheme: 'red', label: 'Needs attention' };
    default:
      return { colorScheme: 'orange', label: 'Incomplete' };
  }
};
